"use client";

import { useState } from "react";
import { FieldValues, FormProvider, useForm } from "react-hook-form";

import { FieldRenderer, type FieldColSpan } from "@/components/forms/core";
import { Button } from "@/components/ui/button";
import { FieldSeparator } from "@/components/ui/field";
import { cn } from "@/lib/utils";
import { typedZodResolver } from "@/lib/utils/typedZodResolver";

import ReCAPTCHAField from "./ReCAPTCHAField";
import type { SchemaFormProps, SectionLayout } from "./schema-form.types";

function getSectionLayoutClass(layout?: SectionLayout, columns?: number) {
  switch (layout) {
    case "grid-2":
      return "grid grid-cols-1 gap-4 sm:grid-cols-2";
    case "grid-3":
      return "grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3";
    case "grid-4":
      return "grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4";
    case "grid-6":
      return "grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-6";
    case "auto-fit":
      return "grid gap-4 [grid-template-columns:repeat(auto-fit,minmax(240px,1fr))]";
    case "grid": {
      const safeColumns = Math.min(Math.max(columns ?? 2, 1), 6);

      switch (safeColumns) {
        case 1:
          return "grid grid-cols-1 gap-4";
        case 2:
          return "grid grid-cols-1 gap-4 sm:grid-cols-2";
        case 3:
          return "grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3";
        case 4:
          return "grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4";
        case 5:
          return "grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-5";
        case 6:
        default:
          return "grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-6";
      }
    }
    default:
      return "flex flex-col gap-5";
  }
}

function getFieldSpanClass(
  layout: SectionLayout | undefined,
  columns: number | undefined,
  colSpan: FieldColSpan | undefined
) {
  if (!colSpan || colSpan === 1 || layout === "stack") {
    return "";
  }

  if (colSpan === "full") {
    return "col-span-full";
  }

  if (layout === "auto-fit") {
    return "";
  }

  const getGridClass = (maxColumns: number) => {
    const safeSpan = Math.min(colSpan, maxColumns);

    switch (safeSpan) {
      case 2:
        return "sm:col-span-2";
      case 3:
        return "sm:col-span-2 lg:col-span-3";
      case 4:
        return "sm:col-span-2 lg:col-span-4";
      default:
        return "";
    }
  };

  switch (layout) {
    case "grid-2":
      return getGridClass(2);
    case "grid-3":
      return getGridClass(3);
    case "grid-4":
      return getGridClass(4);
    case "grid-6":
      return colSpan === 2
        ? "col-span-2"
        : colSpan === 3
        ? "col-span-2 sm:col-span-3"
        : "col-span-2 sm:col-span-3 lg:col-span-4";
    case "grid":
      return getGridClass(Math.min(Math.max(columns ?? 2, 1), 6));
    default:
      return "";
  }
}

export function SchemaForm<
  T extends FieldValues,
  TRow extends Record<string, unknown> = Record<string, unknown>
>({
  schema,
  defaultValues,
  formType = "CREATE",
  sections,
  buttons,
  buttonLayout = "stack",
  recaptcha = false,
  className,
}: SchemaFormProps<T, TRow>) {
  const form = useForm<T>({
    resolver: typedZodResolver(schema),
    defaultValues,
  });

  const isSubmitting = form.formState.isSubmitting;
  const [captchaToken, setCaptchaToken] = useState<string | null>(null);
  const [activeButton, setActiveButton] = useState<string | null>(null);

  const handleSubmit = (buttonKey: string | null) => async (values: T) => {
    if (formType === "VIEW" || (recaptcha && !captchaToken) || !buttonKey) {
      return;
    }

    const button = buttons[buttonKey];
    if (!button?.onSubmit) {
      return;
    }

    await button.onSubmit(values, form);

    if (formType === "CREATE") {
      form.reset(defaultValues);
    }
  };

  const buttonLayoutClass =
    buttonLayout === "stack"
      ? "flex flex-col gap-3"
      : buttonLayout === "right"
      ? "flex flex-wrap justify-end gap-3"
      : buttonLayout === "space-between"
      ? "flex flex-wrap justify-between gap-3"
      : "flex flex-wrap gap-3";

  return (
    <FormProvider {...form}>
      <form
        className={className}
        noValidate
        onSubmit={(event) => {
          event.preventDefault();

          const submitter = (event.nativeEvent as SubmitEvent)
            .submitter as HTMLButtonElement | null;
          const buttonKey = submitter?.name ?? null;

          setActiveButton(buttonKey);
          form.handleSubmit(handleSubmit(buttonKey))();
        }}
      >
        <div className="space-y-8">
          {sections.map((section, index) => (
            <section key={index} className="space-y-4">
              {section.title ? (
                <h3 className="text-lg font-semibold">{section.title}</h3>
              ) : null}
              {section.description ? (
                <p className="text-sm text-muted-foreground">
                  {section.description}
                </p>
              ) : null}
              <div
                className={getSectionLayoutClass(
                  section.layout,
                  section.columns
                )}
              >
                {section.fields.map((field) => (
                  <div
                    key={String(field.name)}
                    className={getFieldSpanClass(
                      section.layout,
                      section.columns,
                      field.colSpan
                    )}
                  >
                    <FieldRenderer control={form.control} {...field} />
                  </div>
                ))}
              </div>
            </section>
          ))}

          {recaptcha ? <ReCAPTCHAField onVerify={setCaptchaToken} /> : null}

          <FieldSeparator className="mb-2" />

          <div
            className={
              buttonLayout === "stack"
                ? "flex flex-col gap-3"
                : "flex flex-wrap justify-end gap-3"
            }
          >
            <div className={buttonLayoutClass}>
              {Object.entries(buttons).map(([key, button]) => {
                const isLoading = isSubmitting && activeButton === key;
                const shouldFillWidth = buttonLayout === "stack";

                return (
                  <Button
                    key={key}
                    name={key}
                    type={button.submit ? "submit" : "button"}
                    variant={button.variant ?? "default"}
                    disabled={isSubmitting}
                    className={cn(
                      "flex min-w-0 cursor-pointer items-center justify-center gap-2",
                      shouldFillWidth ? "w-full" : "w-full sm:w-auto",
                      button.className
                    )}
                  >
                    {isLoading ? (
                      button.loadingLabel ?? "Processing..."
                    ) : (
                      <span className="flex items-center gap-2">
                        {button.iconLeft}
                        {button.label}
                      </span>
                    )}
                  </Button>
                );
              })}
            </div>
          </div>
        </div>
      </form>
    </FormProvider>
  );
}

/** @deprecated Use SchemaForm instead. */
export const FormBuilderStandard = SchemaForm;

"use client";

import { useRef, useEffect } from "react";
import ReCAPTCHA from "react-google-recaptcha";

type Props = {
  onVerify: (token: string | null) => void;
  disabled?: boolean;
};

export default function ReCAPTCHAField({ onVerify, disabled }: Props) {
  const ref = useRef<ReCAPTCHA | null>(null);

  useEffect(() => {
    // reset when re-enabled (optional)
    if (!disabled) {
      ref.current?.reset();
    }
  }, [disabled]);

  return (
    <div className="flex justify-center ">
      <ReCAPTCHA
        ref={ref}
        sitekey={process.env.NEXT_PUBLIC_RECAPTCHA_SITE_KEY!}
        onChange={(token) => onVerify(token)}
        onExpired={() => onVerify(null)}
      />
    </div>
  );
}

import type {
  DefaultValues,
  FieldPath,
  FieldValues,
  UseFormReturn,
} from "react-hook-form";
import type { ReactNode } from "react";
import type { ZodType } from "zod";

import type { FieldRendererProps } from "@/components/forms/core";

export type CRUDFormType = "CREATE" | "UPDATE" | "VIEW";

export type SectionLayout =
  | "stack"
  | "grid"
  | "grid-2"
  | "grid-3"
  | "grid-4"
  | "grid-6"
  | "auto-fit";

export type ButtonLayout = "stack" | "inline" | "right" | "space-between";

export type SchemaFieldConfig<
  T extends FieldValues,
  TName extends FieldPath<T> = FieldPath<T>,
  TRow extends Record<string, unknown> = Record<string, unknown>
> = Omit<FieldRendererProps<T, TName, TRow>, "control">;

export interface SchemaSectionConfig<
  T extends FieldValues,
  TRow extends Record<string, unknown> = Record<string, unknown>
> {
  title?: string;
  description?: string;
  layout?: SectionLayout;
  columns?: number;
  fields: SchemaFieldConfig<T, FieldPath<T>, TRow>[];
}

export interface FormActionConfig<T extends FieldValues> {
  label: string;
  submit?: boolean;
  className?: string;
  loadingLabel?: string;
  variant?: "default" | "secondary" | "destructive" | "outline" | "ghost";
  iconLeft?: ReactNode;
  iconRight?: ReactNode;
  onSubmit?: (values: T, form: UseFormReturn<T>) => void | Promise<void>;
}

export interface SchemaFormProps<
  T extends FieldValues,
  TRow extends Record<string, unknown> = Record<string, unknown>
> {
  schema: ZodType<T>;
  defaultValues: DefaultValues<T>;
  formType?: CRUDFormType;
  sections: SchemaSectionConfig<T, TRow>[];
  buttons: Record<string, FormActionConfig<T>>;
  buttonLayout?: ButtonLayout;
  recaptcha?: boolean;
  className?: string;
}

/** @deprecated Use SchemaFieldConfig instead. */
export type FormBuilderField<T extends FieldValues> = SchemaFieldConfig<T>;
/** @deprecated Use SchemaSectionConfig instead. */
export type FormBuilderSection<T extends FieldValues> = SchemaSectionConfig<T>;
/** @deprecated Use FormActionConfig instead. */
export type FormBuilderButton<T extends FieldValues> = FormActionConfig<T>;
/** @deprecated Use SchemaFormProps instead. */
export type FormBuilderStandardProps<T extends FieldValues> = SchemaFormProps<T>;

import { toast } from "sonner";
import { CheckCircle2, XCircle, Info } from "lucide-react";
import { cn } from "../utils";

const baseClass =
  "flex items-start gap-3 max-w-[420px] whitespace-pre-line break-words text-sm leading-snug p-4 rounded-lg shadow-sm";

interface ToastOptions {
  message: string;
  description?: string;
  icon?: React.ReactNode;
  className?: string;
 
}

export function showSuccess({ message, description, icon, className }: ToastOptions) {
  toast.success(message, {
    icon: icon ?? (
      <CheckCircle2 className="w-5 h-5 text-green-600 shrink-0 mt-0.5" />
    ),
    description: description,
    className: cn(`${baseClass} bg-green-50 text-green-700 border border-green-200`, className),
  });
}


export function showError({ message, description, icon, className }: ToastOptions) {
  toast.error(message, {
    icon: icon ?? (
    <XCircle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
    ),
    description: description,
    className: cn(`${baseClass} bg-red-50 text-red-700 border border-red-200`, className),
  });
}



export function showInfo(message: string) {
  toast(message, {
    icon: <Info className="w-5 h-5 text-blue-500 shrink-0 mt-0.5" />,
    className: `${baseClass} bg-blue-50 text-blue-700 border border-blue-200`,
  });
}

import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import type { FieldValues, Resolver } from "react-hook-form";

/**
 * Typed wrapper around zodResolver.
 * This keeps your FormBuilder generics clean and avoids resolver type errors.
 */
export function typedZodResolver<TValues extends FieldValues>(
  schema: z.ZodType<TValues>
): Resolver<TValues> {
  // We cast through unknown because zodResolver’s internal types are broader
  
  return zodResolver(schema as never) as unknown as Resolver<TValues>;
}
